var e=[{id:`L2_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`하아...... 하아......!`,JPN:`はあ……はあ……！`,ENG:`*Huff... Huff...*`,TWN:`哈啊……哈啊……！`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CRIMINAL_NPC_BOSS2_NULL`,text:{KOREA:`분명히 내 공격을 정면으로 맞은 것 같은데...... 어떻게 살아 있는 거지?`,JPN:`確かに俺の攻撃を正面から受けたはずだが……なんで生きているんだ？`,ENG:`I was pretty sure my attack landed right on you... How did you survive that?`,TWN:`明明正面擊中了她……為什麼沒死？`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CRIMINAL_NPC_BOSS2_NULL`,text:{KOREA:`맷집이 좋은 건지, 내가 힘 조절에 실패한 건지 모르겠군.`,JPN:`打たれ強いのか、俺が手加減に失敗したのかわからないな。`,ENG:`I don't know if you took the blow well or if I went too easy on you.`,TWN:`不知道是妳耐打，還是我沒調整好力道。`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CRIMINAL_NPC_BOSS2_NULL`,text:{KOREA:`어쨌든 숨바꼭질은 끝났어.`,JPN:`とにかく、かくれんぼはおしまいだ。`,ENG:`In any case, enough with the hide and seek.`,TWN:`不管怎樣，捉迷藏就到此為止吧。`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`CRIMINAL_NPC_BOSS2_NULL`,text:{KOREA:`슬슬 엎드려서 빌어 보는 게 어때.`,JPN:`そろそろ命乞いでもしたらどうだ。`,ENG:`Why don't you get on your knees and beg?`,TWN:`不如出來乖乖投降吧。`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`CRIMINAL_NPC_BOSS2_NULL`,text:{KOREA:`정성을 생각해서 목숨만은 살려 줄지도 모르잖아.`,JPN:`ここまで耐えた努力を称えて、命だけは助けてやるかもしれんぞ。`,ENG:`Maybe I'll be generous and let you live.`,TWN:`說不定我會饒妳一命。`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`네놈들에게 엎드리느니 차라리 내 손으로 머리통에 총알을 박겠어.`,JPN:`お前らに命乞いをするなら、自分で頭をぶち抜いて死んだ方がマシだ。`,ENG:`I'd rather shoot myself in the head than kneel before you scumbags.`,TWN:`向你投降，還不如親手開槍射穿我的頭顱。`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`힘 자랑은 다 끝났나 보지? 그럼 이젠 내 차례야.`,JPN:`力自慢はもう終わりか？　じゃあ、私の番だ。`,ENG:`You done flexing your stuff? Then it's my turn now.`,TWN:`你的表演結束了嗎？那接下來就輪到我了。`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CRIMINAL_NPC_BOSS2_NULL`,text:{KOREA:`수류탄? 또 가짜 모형이냐?`,JPN:`手榴弾？　また偽物か？`,ENG:`A grenade? Is that one of your plastic toys again?`,TWN:`手榴彈？又是那個玩具嗎？`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`가짜인지 아닌지는 네 몸으로 직접 확인해 보시지.`,JPN:`偽物かどうか、その体で確かめてみろ。`,ENG:`Why don't you find out for yourself?`,TWN:`你來親自體驗一下是不是假的。`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CRIMINAL_NPC_BOSS2_NULL`,text:{KOREA:`뭐야? 어디로 던지는 거냐?`,JPN:`なんだ？　どこに投げるんだ？`,ENG:`Huh? Where are you throwing that thing?`,TWN:`什麼？妳往哪裡扔？`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CRIMINAL_NPC_BOSS2_NULL`,text:{KOREA:`자포자기라도 했나? 이래서야 일부러 놀라줄 수도 없잖아.`,JPN:`もう諦めモードか？　これじゃビックリするふりもできねえな。`,ENG:`Are you just giving up now? I don't even know how to react to that.`,TWN:`自暴自棄了嗎？這也太無趣了吧。`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`글쎄. 자포자기인지 어떤지는......`,JPN:`さあね。諦めなのかどうかは……`,ENG:`Well, we'll see about that...`,TWN:`是不是自暴自棄……`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`YURI_MILITIA_NULL_NULL`,text:{KOREA:`하늘이 대답해 주겠지.`,JPN:`空が教えてくれるさ。`,ENG:`Heads up!`,TWN:`老天會告訴你答案。`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`CRIMINAL_NPC_BOSS2_NULL`,text:{KOREA:`......뭐?`,JPN:`……は？`,ENG:`What?`,TWN:`……什麼？`},stage:{bg:`OFFICE_MESSED`,slots:{L:null,C:{char_id:`YURI_MILITIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`CRIMINAL_NPC_BOSS2_NULL`,text:{KOREA:`크으윽......`,JPN:`くうっ……`,ENG:`Ugh...`,TWN:`呃啊啊……`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`CRIMINAL_NPC_BOSS2_NULL`,text:{KOREA:`천장을 통째로 무너트리다니, 미리 기둥을 약화시켜 둔 건가?`,JPN:`天井を丸ごと崩すとは、事前に柱を壊していたのか。`,ENG:`How did she bring down the ceiling? Did she damage the pillars beforehand?`,TWN:`竟然直接炸毀了天花板，難道事先弱化了柱子？`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:null,R:null}}}];export{e as default};